if(context.global.sequenceRx===undefined || context.global.sequenceRx===null) context.global.sequenceRx = 0;
if(context.global.sequenceTx===undefined || context.global.sequenceTx===null) context.global.sequenceTx = 0;
if(context.global.dataTransfer===undefined || context.global.dataTransfer===null) context.global.dataTransfer = false;

var bufferIn = [];
var bufferOut = [];

if(msg.payload === "START") {
    context.global.sequenceRx = 0;
    context.global.sequenceTx = 0;
    bufferOut = [104, 4, 7, 0, 0, 0];
}
else if(msg.payload === "STOP") {
    bufferOut = [104, 4, 19, 0, 0, 0];
}
else if(msg.payload === "TEST") {
    bufferOut = [104, 4, 67, 0, 0, 0];
}
else if(msg.payload === "IC") {
    bufferOut = [104, 14, 0, 0, 0, 0, 100, 1, 6, 0, 1, 0, 0, 0, 0, 20];
}
else {
    var rawData = msg.payload;
    if(!Buffer.isBuffer(rawData)) { rawData = Buffer.from(rawData); }

    // Strip APCI start byte (0x68) and length
    for(var x = 2; x < rawData.length; x++) bufferIn.push(rawData[x]);

    if (bufferIn.length > 0 && !bitRead(bufferIn[0], 0)) { // I-FORMAT
        context.global.sequenceRx++; 
        var type = bufferIn[4];
        var count = bufferIn[5] & 127;
        var ca = bufferIn[8] | (bufferIn[9] << 8);

        // Type 34 Parsing: M_ME_TD_1 (12 Bytes per data object structure)
        if (type === 34 || type === 0x22) {
            for (var h = 0; h < count; h++) {
                var baseIdx = 10 + (h * 12); 
                if(baseIdx + 4 < bufferIn.length) {
                    var ioa = bufferIn[baseIdx] | (bufferIn[baseIdx + 1] << 8) | (bufferIn[baseIdx + 2] << 16);

                    // FIXED: Correctly parse 16-bit signed normalized integer telegram value
                    var rawVal = bufferIn[baseIdx + 3] | (bufferIn[baseIdx + 4] << 8);

                    // Handle standard 16-bit sign extension for negative steps
                    if (rawVal & 0x8000) {
                        rawVal = rawVal - 0x10000;
                    }

                    // FIXED MATH: IEC 104 Normalized values are scaled by 32767
                    var scaledFloat = rawVal / 32767.0; 

                    var outMsg = {
                        payload: Number(scaledFloat.toFixed(3)), // This will output exactly 0.200
                        type: "M_ME_TD_1",
                        ca: Number(ca),
                        ioa: Number(ioa),
                        value: Number(scaledFloat.toFixed(3))
                    };
                    node.send([null, outMsg]);
                }
            }
            inviaS(); 
        }
        else {
            inviaS(); 
        }
    }
}

function inviaBuf(buffer, lung) {
    bufferOut.push(0x68); bufferOut.push(lung); 
    for (var i = 0; i < lung; i++) bufferOut.push(buffer[i]);
}
function inviaU(msgByte) { var buf = [msgByte,0,0,0]; inviaBuf(buf, 4); }
function inviaS() {
    var buf = [0x01,0,0,0];
    buf[2] = (context.global.sequenceRx << 1) & 255;
    buf[3] = (context.global.sequenceRx >> 7) & 255;
    inviaBuf(buf, 4);
}
function bitRead(num,bit) { return ((num & (1 << bit)) !== 0); }

if(bufferOut.length > 0) { return [{ payload: Buffer.from(bufferOut) }, null]; }
return null;

