function constructAlarmAddressSpace(server, addressSpace, eventObjects, done) {
  const opcua = coreServer.choreCompact.opcua;
  const LocalizedText = opcua.LocalizedText;
  const namespace = addressSpace.getOwnNamespace();

  // Initialize our tracking variable inside the flow memory if it doesn't exist
  if (sandboxFlowContext.get("TAG1") === undefined || sandboxFlowContext.get("TAG1") === null) {
    sandboxFlowContext.set("TAG1", 25);
  }

  // Register TAG1 directly inside the server's Objects root folder mapping
  namespace.addVariable({
    organizedBy: addressSpace.rootFolder.objects,
    nodeId: "ns=1;s=TAG1",
    browseName: "TAG1",
    displayName: new LocalizedText({ text: "TAG1", locale: "en-US" }),
    dataType: "Int32",
    value: {
      get: function () {
        // Pulls the live integer value directly out of the memory context
        const val = parseInt(sandboxFlowContext.get("TAG1")) || 25;
        return new opcua.Variant({ dataType: opcua.DataType.Int32, value: val });
      },
      set: function (variant) {
        sandboxFlowContext.set("TAG1", parseInt(variant.value));
        return opcua.StatusCodes.Good;
      }
    }
  });

  done();
}
